// 引入 stylex
import stylex from '@universe-design/stylex';
import React from 'react';

// 创建样式实例
const xsDiv = stylex.create({
  fontSize: 16,
  color: 'red',
  borderWidth: '1px',
  borderStyle: 'solid',
  borderColor: 'blue',
});

// 应用样式实例
export default () => <div className={stylex(xsDiv)}>stylex</div>;
